import{_ as n,o as a,c as o,ak as r}from"./chunks/framework.Dx0ZwfXr.js";const m=JSON.parse('{"title":"RdpControl","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-rdpcontrol.md","filePath":"api/reference/royalapps-community-rdp-winforms-rdpcontrol.md"}'),t={name:"api/reference/royalapps-community-rdp-winforms-rdpcontrol.md"};function i(s,e,d,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="rdpcontrol" tabindex="-1"><code>RdpControl</code> <a class="header-anchor" href="#rdpcontrol" aria-label="Permalink to “RdpControl”">​</a></h1><p>A WinForms control that hosts an embedded RDP session or launches an external RDP client process.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.RdpControl</span></span></code></pre></div><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="currentzoomlevel-int" tabindex="-1"><code>CurrentZoomLevel</code> (<code>int</code>) <a class="header-anchor" href="#currentzoomlevel-int" aria-label="Permalink to “CurrentZoomLevel (int)”">​</a></h3><p>Gets the current zoom level in percentage of the remote desktop session.</p><h3 id="externalprocessid-int" tabindex="-1"><code>ExternalProcessId</code> (<code>int</code>?) <a class="header-anchor" href="#externalprocessid-int" aria-label="Permalink to “ExternalProcessId (int?)”">​</a></h3><p>Gets the external process ID while <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-rdpcontrol">RdpControl.RdpConfiguration</a> uses <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpsessionmode">RdpSessionMode.External</a> and the process is still running.</p><h3 id="externalsessionwindowhandle-nint" tabindex="-1"><code>ExternalSessionWindowHandle</code> (<code>nint</code>?) <a class="header-anchor" href="#externalsessionwindowhandle-nint" aria-label="Permalink to “ExternalSessionWindowHandle (nint?)”">​</a></h3><p>Gets the last known top-level external session window handle while <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-rdpcontrol">RdpControl.RdpConfiguration</a> uses <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpsessionmode">RdpSessionMode.External</a>.</p><h3 id="logger-ilogger" tabindex="-1"><code>Logger</code> (<code>ILogger</code>) <a class="header-anchor" href="#logger-ilogger" aria-label="Permalink to “Logger (ILogger)”">​</a></h3><p>Gets or sets the logger used by the control.</p><h3 id="rdpclient-irdpclient" tabindex="-1"><code>RdpClient</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient</a>?) <a class="header-anchor" href="#rdpclient-irdpclient" aria-label="Permalink to “RdpClient (IRdpClient?)”">​</a></h3><p>Access to the embedded RDP client and its events, methods, and properties. Returns <code>null</code> while <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-rdpcontrol">RdpControl.RdpConfiguration</a> uses <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpsessionmode">RdpSessionMode.External</a>.</p><h3 id="rdpconfiguration-rdpclientconfiguration" tabindex="-1"><code>RdpConfiguration</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpclientconfiguration">RdpClientConfiguration</a>) <a class="header-anchor" href="#rdpconfiguration-rdpclientconfiguration" aria-label="Permalink to “RdpConfiguration (RdpClientConfiguration)”">​</a></h3><p>Gets or sets the configuration used to create and connect the RDP session.</p><h3 id="sessioncapture-bitmap" tabindex="-1"><code>SessionCapture</code> (<code>Bitmap</code>?) <a class="header-anchor" href="#sessioncapture-bitmap" aria-label="Permalink to “SessionCapture (Bitmap?)”">​</a></h3><p>Gets the last captured screenshot of the session, when session capture is enabled.</p><h3 id="wassuccessfullyconnected-bool" tabindex="-1"><code>WasSuccessfullyConnected</code> (<code>bool</code>) <a class="header-anchor" href="#wassuccessfullyconnected-bool" aria-label="Permalink to “WasSuccessfullyConnected (bool)”">​</a></h3><p>Gets a value indicating whether the session has connected successfully at least once.</p><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to “Events”">​</a></h2><h3 id="beforeremotedesktopsizechanged" tabindex="-1"><code>BeforeRemoteDesktopSizeChanged</code> <a class="header-anchor" href="#beforeremotedesktopsizechanged" aria-label="Permalink to “BeforeRemoteDesktopSizeChanged”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<code>CancelEventArgs</code>&gt;?</p><p>Raised before the remote desktop size changes. Set <code>System.ComponentModel.CancelEventArgs.Cancel</code> to cancel the resize operation.</p><h3 id="externalsessionwindowchanged" tabindex="-1"><code>ExternalSessionWindowChanged</code> <a class="header-anchor" href="#externalsessionwindowchanged" aria-label="Permalink to “ExternalSessionWindowChanged”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-events-externalwindowchangedeventargs">ExternalWindowChangedEventArgs</a>&gt;?</p><p>Raised when the tracked top-level window for an external session is discovered, changes, or disappears.</p><h3 id="onclientareaclicked" tabindex="-1"><code>OnClientAreaClicked</code> <a class="header-anchor" href="#onclientareaclicked" aria-label="Permalink to “OnClientAreaClicked”">​</a></h3><p>Handler Type: <code>EventHandler</code>?</p><p>Raised when the user clicks inside the remote desktop session and click detection is enabled.</p><h3 id="onconfirmclose" tabindex="-1"><code>OnConfirmClose</code> <a class="header-anchor" href="#onconfirmclose" aria-label="Permalink to “OnConfirmClose”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<code>IMsTscAxEvents_OnConfirmCloseEvent</code>&gt;?</p><p>Raised when the client calls the RequestClose method.</p><h3 id="onconnected" tabindex="-1"><code>OnConnected</code> <a class="header-anchor" href="#onconnected" aria-label="Permalink to “OnConnected”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-events-connectedeventargs">ConnectedEventArgs</a>&gt;?</p><p>Raised when the session has started.</p><h3 id="ondisconnected" tabindex="-1"><code>OnDisconnected</code> <a class="header-anchor" href="#ondisconnected" aria-label="Permalink to “OnDisconnected”">​</a></h3><p>Handler Type: <code>EventHandler</code>&lt;<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-events-disconnectedeventargs">DisconnectedEventArgs</a>&gt;?</p><p>Raised when the session has been disconnected or the external client process exits.</p><h3 id="onrequestcontainerminimize" tabindex="-1"><code>OnRequestContainerMinimize</code> <a class="header-anchor" href="#onrequestcontainerminimize" aria-label="Permalink to “OnRequestContainerMinimize”">​</a></h3><p>Handler Type: <code>EventHandler</code>?</p><p>Raised when the user presses the Minimize button on the connection bar in full-screen mode. This is a request for the container application to minimize itself.</p><h3 id="onrequestleavefullscreen" tabindex="-1"><code>OnRequestLeaveFullScreen</code> <a class="header-anchor" href="#onrequestleavefullscreen" aria-label="Permalink to “OnRequestLeaveFullScreen”">​</a></h3><p>Handler Type: <code>EventHandler</code>?</p><p>Raised when the client requests to leave full-screen mode or <code>ContainerHandledFullScreen</code> has been set to a nonzero value.</p><h3 id="rdpclientconfigured" tabindex="-1"><code>RdpClientConfigured</code> <a class="header-anchor" href="#rdpclientconfigured" aria-label="Permalink to “RdpClientConfigured”">​</a></h3><p>Handler Type: <code>EventHandler</code>?</p><p>Raised after the <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-controls-clients-irdpclient">IRdpClient</a> has been created and configured, but before the connection is established. This allows additional customization that is not covered by <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-rdpcontrol">RdpControl.RdpConfiguration</a>.</p><h3 id="remotedesktopsizechanged" tabindex="-1"><code>RemoteDesktopSizeChanged</code> <a class="header-anchor" href="#remotedesktopsizechanged" aria-label="Permalink to “RemoteDesktopSizeChanged”">​</a></h3><p>Handler Type: <code>EventHandler</code>?</p><p>Raised when the remote desktop size has changed.</p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><h3 id="connect" tabindex="-1"><code>Connect()</code> <a class="header-anchor" href="#connect" aria-label="Permalink to “Connect()”">​</a></h3><p>Returns: <code>void</code></p><p>Starts the remote desktop connection. Depending on <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpclientconfiguration">RdpClientConfiguration.SessionMode</a>, this either creates the embedded client control or launches an external client process.</p><p><a href="./../">Back to API index</a></p>',57)])])}const f=n(t,[["render",i]]);export{m as __pageData,f as default};
